// ── Utility: format currency ─────────────────────────────────────────────
function formatCurrency(val) {
  const num = parseInt(String(val).replace(/[^0-9]/g, ''), 10) || 0;
  return num.toLocaleString('en-US');
}

// ── SVG Progress Circle ──────────────────────────────────────────────────
function ProgressCircle({ percent, size = 180, strokeWidth = 6 }) {
  const radius = (size - strokeWidth) / 2;
  const circumference = 2 * Math.PI * radius;
  const offset = circumference - (percent / 100) * circumference;

  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      {/* Background circle */}
      <circle
        cx={size / 2}
        cy={size / 2}
        r={radius}
        fill="none"
        stroke={C.border}
        strokeWidth={strokeWidth}
      />
      {/* Progress arc */}
      <circle
        cx={size / 2}
        cy={size / 2}
        r={radius}
        fill="none"
        stroke="url(#greenGradient)"
        strokeWidth={strokeWidth}
        strokeLinecap="round"
        strokeDasharray={circumference}
        strokeDashoffset={offset}
        transform={`rotate(-90 ${size / 2} ${size / 2})`}
        style={{ transition: 'stroke-dashoffset 0.6s ease' }}
      />
      {/* Gradient def */}
      <defs>
        <linearGradient id="greenGradient" x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" stopColor="#22C55E" />
          <stop offset="100%" stopColor="#16A34A" />
        </linearGradient>
      </defs>
      {/* Center text */}
      <text
        x="50%"
        y="50%"
        textAnchor="middle"
        dominantBaseline="central"
        fill={C.text}
        fontFamily={C.mono}
        fontSize={size * 0.22}
        fontWeight={700}
      >
        {Math.round(percent)}%
      </text>
    </svg>
  );
}

// ── Pulsing Green Dot ────────────────────────────────────────────────────
function PulsingDot({ size = 10, style: extra = {} }) {
  return (
    <span style={{
      display: 'inline-block', width: size, height: size,
      borderRadius: '50%', background: C.green,
      boxShadow: `0 0 ${size}px ${C.greenGlow}, 0 0 ${size * 2}px ${C.greenDim}`,
      animation: 'aura-pulse 2s ease-in-out infinite',
      ...extra,
    }} />
  );
}

// ── AnimatedCounter ──────────────────────────────────────────────────────
function AnimatedCounter({ target, duration = 1500, prefix = '', suffix = '' }) {
  const [val, setVal] = useState(0);
  const ref = useRef(null);

  useEffect(() => {
    const start = performance.now();
    function tick(now) {
      const elapsed = now - start;
      const progress = Math.min(elapsed / duration, 1);
      // Ease out cubic
      const eased = 1 - Math.pow(1 - progress, 3);
      setVal(Math.round(eased * target));
      if (progress < 1) ref.current = requestAnimationFrame(tick);
    }
    ref.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(ref.current);
  }, [target, duration]);

  return <span>{prefix}{val.toLocaleString()}{suffix}</span>;
}

