// ═══════════════════════════════════════════════════════════════════════════
//  STEP 3 — SYSTEM STARTUP (Animated Progress)
// ═══════════════════════════════════════════════════════════════════════════
const STARTUP_STAGES = [
  { msg: 'Loading market data...', end: 20 },
  { msg: 'Initializing 83 strategies...', end: 40 },
  { msg: 'Connecting to signal engine...', end: 60 },
  { msg: 'Generating first signals...', end: 80 },
  { msg: 'System ready.', end: 100 },
];

function StepSystemStartup({ onComplete }) {
  const [progress, setProgress] = useState(0);
  const [stageIdx, setStageIdx] = useState(0);
  const [completedStages, setCompletedStages] = useState([]);
  const timerRef = useRef(null);

  useEffect(() => {
    let currentStage = 0;

    function advanceStage() {
      if (currentStage >= STARTUP_STAGES.length) {
        // Done. Pause 500ms then advance
        setTimeout(onComplete, 500);
        return;
      }

      const stage = STARTUP_STAGES[currentStage];
      setStageIdx(currentStage);

      // Animate progress to stage.end over ~800ms
      const startVal = currentStage === 0 ? 0 : STARTUP_STAGES[currentStage - 1].end;
      const targetVal = stage.end;
      const duration = 800;
      const startTime = performance.now();

      function tick(now) {
        const elapsed = now - startTime;
        const t = Math.min(elapsed / duration, 1);
        const eased = 1 - Math.pow(1 - t, 3);
        setProgress(startVal + (targetVal - startVal) * eased);
        if (t < 1) {
          timerRef.current = requestAnimationFrame(tick);
        } else {
          // Stage complete
          setCompletedStages(prev => [...prev, currentStage]);
          currentStage++;
          // Wait before next stage
          setTimeout(advanceStage, currentStage >= STARTUP_STAGES.length ? 0 : 200);
        }
      }

      timerRef.current = requestAnimationFrame(tick);
    }

    // Start after a brief delay
    const startDelay = setTimeout(advanceStage, 300);

    return () => {
      clearTimeout(startDelay);
      cancelAnimationFrame(timerRef.current);
    };
  }, [onComplete]);

  return (
    <div style={{
      display: 'flex', flexDirection: 'column', alignItems: 'center',
      justifyContent: 'center', height: '100vh', width: '100vw',
      background: C.bg,
    }}>
      <ProgressCircle percent={progress} size={200} strokeWidth={6} />

      <div style={{
        marginTop: 40, display: 'flex', flexDirection: 'column',
        alignItems: 'flex-start', gap: 12, minWidth: 300,
      }}>
        {STARTUP_STAGES.map((stage, i) => {
          const isActive = i === stageIdx && !completedStages.includes(i);
          const isDone = completedStages.includes(i);
          const isHidden = i > stageIdx;

          return (
            <motion.div
              key={i}
              initial={{ opacity: 0, x: -12 }}
              animate={{
                opacity: isHidden ? 0 : 1,
                x: isHidden ? -12 : 0,
              }}
              transition={{ duration: 0.3 }}
              style={{
                display: 'flex', alignItems: 'center', gap: 10,
                fontFamily: C.mono, fontSize: 13,
                color: isDone ? C.green : isActive ? C.text : C.textMuted,
              }}
            >
              {isDone ? (
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={C.green} strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                  <polyline points="20 6 9 17 4 12" />
                </svg>
              ) : isActive ? (
                <PulsingDot size={8} style={{ marginLeft: 4, marginRight: 4 }} />
              ) : (
                <span style={{ width: 16, height: 16 }} />
              )}
              {stage.msg}
            </motion.div>
          );
        })}
      </div>
    </div>
  );
}

