// ═══════════════════════════════════════════════════════════════════════════
//  MAIN WIZARD
// ═══════════════════════════════════════════════════════════════════════════
export default function OnboardingWizard() {
  const navigate = useNavigate();
  const [step, setStep] = useState(0);
  const [direction, setDirection] = useState(1);
  const [config, setConfig] = useState({
    mode: 'standalone',
    capital: '10000',
    markets: ['us_equities'],
    preset: 'balanced',
  });

  // If onboarding already completed, go home
  useEffect(() => {
    if (localStorage.getItem(STORAGE_KEY_COMPLETED) === 'true') {
      navigate('/home', { replace: true });
    }
  }, [navigate]);

  const goToStep = useCallback((next) => {
    setDirection(next > step ? 1 : -1);
    setStep(next);
  }, [step]);

  const saveConfig = useCallback(() => {
    localStorage.setItem(STORAGE_KEY_CONFIG, JSON.stringify(config));
  }, [config]);

  const handleSkip = useCallback(() => {
    // Save defaults
    const defaults = {
      mode: 'standalone',
      capital: '10000',
      markets: ['us_equities'],
      preset: 'balanced',
    };
    setConfig(defaults);
    localStorage.setItem(STORAGE_KEY_CONFIG, JSON.stringify(defaults));
    goToStep(3); // Jump to system startup
  }, [goToStep]);

  const handleStartSystem = useCallback(() => {
    saveConfig();
    goToStep(3);
  }, [saveConfig, goToStep]);

  const handleStartupComplete = useCallback(() => {
    goToStep(4);
  }, [goToStep]);

  const handleViewDashboard = useCallback(() => {
    // Set overlay flag so App renders the overlay on top of /home
    saveConfig();
    localStorage.setItem(STORAGE_KEY_OVERLAY, 'true');
    navigate('/home', { replace: true });
  }, [navigate, saveConfig]);

  return (
    <>
      <style>{`
        @keyframes aura-pulse {
          0%, 100% { opacity: 1; transform: scale(1); }
          50% { opacity: 0.6; transform: scale(1.15); }
        }
      `}</style>
      <div style={{
        position: 'fixed', inset: 0,
        background: step === 0 ? '#000' : C.bg,
        overflow: 'auto',
        transition: 'background 0.5s ease',
      }}>
        <AnimatePresence mode="wait" custom={direction}>
          {step === 0 && (
            <motion.div
              key="step-0"
              variants={stepVariants}
              custom={direction}
              initial="enter"
              animate="center"
              exit="exit"
              transition={stepTransition}
            >
              <StepSplash onComplete={() => goToStep(1)} />
            </motion.div>
          )}

          {step === 1 && (
            <motion.div
              key="step-1"
              variants={stepVariants}
              custom={direction}
              initial="enter"
              animate="center"
              exit="exit"
              transition={stepTransition}
            >
              <StepModeSelection
                config={config}
                setConfig={setConfig}
                onContinue={() => goToStep(2)}
                onSkip={handleSkip}
              />
            </motion.div>
          )}

          {step === 2 && (
            <motion.div
              key="step-2"
              variants={stepVariants}
              custom={direction}
              initial="enter"
              animate="center"
              exit="exit"
              transition={stepTransition}
            >
              <StepQuickSetup
                config={config}
                setConfig={setConfig}
                onStart={handleStartSystem}
                onSkip={handleSkip}
              />
            </motion.div>
          )}

          {step === 3 && (
            <motion.div
              key="step-3"
              variants={stepVariants}
              custom={direction}
              initial="enter"
              animate="center"
              exit="exit"
              transition={stepTransition}
            >
              <StepSystemStartup onComplete={handleStartupComplete} />
            </motion.div>
          )}

          {step === 4 && (
            <motion.div
              key="step-4"
              variants={stepVariants}
              custom={direction}
              initial="enter"
              animate="center"
              exit="exit"
              transition={stepTransition}
            >
              <StepFirstSignals onContinue={handleViewDashboard} />
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </>
  );
}

