// ═══════════════════════════════════════════════════════════════════════════
//  EXPORTED OVERLAY WRAPPER — renders on top of the dashboard
//  Used in App.jsx to show the Step 5 overlay after onboarding navigates
//  to /home. Checks localStorage for the overlay flag.
// ═══════════════════════════════════════════════════════════════════════════
export function OnboardingOverlay() {
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    if (localStorage.getItem(STORAGE_KEY_OVERLAY) === 'true') {
      // Small delay to let the dashboard render first
      const t = setTimeout(() => setVisible(true), 600);
      return () => clearTimeout(t);
    }
  }, []);

  const handleDismiss = useCallback(() => {
    setVisible(false);
    localStorage.removeItem(STORAGE_KEY_OVERLAY);
    localStorage.setItem(STORAGE_KEY_COMPLETED, 'true');
  }, []);

  if (!visible) return null;

  return (
    <>
      <style>{`
        @keyframes aura-pulse {
          0%, 100% { opacity: 1; transform: scale(1); }
          50% { opacity: 0.6; transform: scale(1.15); }
        }
      `}</style>
      <AnimatePresence>
        <DashboardOverlay onDismiss={handleDismiss} />
      </AnimatePresence>
    </>
  );
}
